import { Layout, Calendar, MoreVertical, SquarePlus } from 'lucide-react';
import { useState } from 'react';
import { accessData } from '../../data/mockData';
import SearchBar from '../ui/SearchBar';
import DatePicker from 'react-datepicker';
import "react-datepicker/dist/react-datepicker.css";
import { useNavigate } from 'react-router-dom';

export default function AccessManagementContent() {
  const [sortBy, setSortBy] = useState(null);
  const [sortOrder, setSortOrder] = useState('asc'); // or 'desc'
  const [showDatePicker, setShowDatePicker] = useState(false);
  const [selectedDate, setSelectedDate] = useState(new Date());
  const [showCalendar, setShowCalendar] = useState(false);
  const navigate = useNavigate();
  const [openMenuIndex, setOpenMenuIndex] = useState(null);
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 10; // ou 5, 20, etc.

  const handlePageChange = (pageNumber) => {
    setCurrentPage(pageNumber);
  };


  const toggleMenu = (index) => {
    setOpenMenuIndex(openMenuIndex === index ? null : index);
  };

  const toggleDatePicker = () => {
    setShowDatePicker(!showDatePicker);
  };

  const handleSort = (column) => {
    if (sortBy === column) {
      // Toggle order
      setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc');
    } else {
      setSortBy(column);
      setSortOrder('asc');
    }
  };

  const sortedData = [...accessData].sort((a, b) => {
    if (!sortBy) return 0;

    const valA = a[sortBy];
    const valB = b[sortBy];

    if (typeof valA === 'string') {
      return sortOrder === 'asc'
        ? valA.localeCompare(valB)
        : valB.localeCompare(valA);
    }

    if (typeof valA === 'number') {
      return sortOrder === 'asc' ? valA - valB : valB - valA;
    }

    return 0;
  });
  const totalPages = Math.ceil(sortedData.length / itemsPerPage);
  const paginatedData = sortedData.slice(
    (currentPage - 1) * itemsPerPage,
    currentPage * itemsPerPage
  );

  const renderSortIcon = (column) => {
    if (sortBy !== column) return null;
    return sortOrder === 'asc' ? ' ▲' : ' ▼';
  };

  return (
    <div className="p-6">
      <div className="flex justify-between items-center mb-6">
        <SearchBar placeholder="Search access ID..." />
        <button onClick={() => navigate('/access/add')} className="bg-blue-800 text-white px-4 py-2 rounded-md flex items-center">
          <SquarePlus className="mr-2" size={16} />
          <span>Add To List</span>
        </button>
      </div>

      <div className="flex justify-between items-center mb-6">
        <div>
          <h1 className="text-2xl font-bold text-gray-800">Access Management</h1>
          <p className="text-gray-500">Display all the Access registered</p>
        </div>
        <div className="flex items-center gap-4">
          <div className="text-sm">
            Total <span className="font-bold">{accessData.length}</span> Access
          </div>
          <div className="flex items-center gap-2">
            <select className="border rounded-md px-3 py-1 text-sm">
              <option>Platform</option>
            </select>
          </div>
          <div className="relative inline-block">
            <button
              onClick={() => setShowCalendar(!showCalendar)}
              className="flex items-center bg-white border rounded-md px-4 py-2 text-gray-700 shadow-sm"
            >
              <span>{selectedDate.toDateString()}</span>
              <Calendar className="ml-2" size={16} />
            </button>

            {showCalendar && (
              <div
                className="absolute z-50 mt-2 border bg-white rounded-lg shadow-lg"
                style={{
                  maxWidth: "100vw",
                  overflowX: "auto",
                  right: 0, // optionnel
                }}
              >
                <DatePicker
                  selected={selectedDate}
                  onChange={(date) => {
                    setSelectedDate(date);
                    setShowCalendar(false);
                  }}
                  inline
                  calendarStartDay={1}
                />
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Table */}
      <div className="bg-white rounded-lg shadow-sm overflow-hidden">
        <table className="min-w-full relative">
          <thead>
            <tr className="border-b">
              {['id', 'login', 'name', 'modifyDate', 'ticket', 'platform'].map((col) => (
                <th
                  key={col}
                  className="py-3 px-4 text-left text-sm font-medium text-gray-500 cursor-pointer"
                  onClick={() => handleSort(col)}
                >
                  {col.charAt(0).toUpperCase() + col.slice(1)}{renderSortIcon(col)}
                </th>
              ))}
              <th className="py-3 px-4 text-left text-sm font-medium text-gray-500"></th>
            </tr>
          </thead>
          <tbody>
            {paginatedData.map((item, index) => (
              <tr key={index} className="border-b hover:bg-gray-50 relative">
                <td className="py-3 px-4 text-sm text-gray-700">{item.id}</td>
                <td className="py-3 px-4 text-sm text-gray-700">{item.login}</td>
                <td className="py-3 px-4 text-sm text-gray-700">{item.name}</td>
                <td className="py-3 px-4 text-sm text-gray-700">{item.modifyDate}</td>
                <td className="py-3 px-4 text-sm text-gray-700">{item.ticket}</td>
                <td className="py-3 px-4">
                  {item.platform && (
                    <span className={`px-2 py-1 text-xs rounded ${item.platform === 'RBS' ? 'bg-blue-100 text-blue-700' :
                      item.platform === 'VOCALCOM' ? 'bg-gray-100 text-gray-700' :
                        'bg-blue-100 text-blue-700'
                      }`}>
                      {item.platform}
                    </span>
                  )}
                </td>
                <td className="py-3 px-4 relative">
                  <button onClick={() => toggleMenu(index)}>
                    <MoreVertical size={16} className="text-gray-500" />
                  </button>
                  {openMenuIndex === index && (
                    <div className="absolute right-4 top-8 bg-white border rounded shadow z-10 text-sm">
                      <button
                        className="block px-4 py-2 hover:bg-gray-100 w-full text-left"
                        onClick={() => {
                          // handleViewDetails(item);
                          setOpenMenuIndex(null);
                        }}
                      >
                        View
                      </button>
                      <button
                        className="block px-4 py-2 hover:bg-gray-100 w-full text-left"
                        onClick={() => {
                          // handleEdit(item);
                          setOpenMenuIndex(null);
                        }}
                      >
                        Edit
                      </button>
                    </div>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>

        {/* Pagination Controls */}
        <div className="flex justify-center items-center gap-2 p-4">
          <button
            onClick={() => handlePageChange(currentPage - 1)}
            disabled={currentPage === 1}
            className="px-3 py-1 text-sm rounded border disabled:opacity-50"
          >
            Previous
          </button>

          {Array.from({ length: totalPages }, (_, i) => i + 1).map((page) => (
            <button
              key={page}
              onClick={() => handlePageChange(page)}
              className={`px-3 py-1 text-sm rounded border ${currentPage === page ? 'bg-blue-800 text-white' : 'bg-white text-gray-800'
                }`}
            >
              {page}
            </button>
          ))}

          <button
            onClick={() => handlePageChange(currentPage + 1)}
            disabled={currentPage === totalPages}
            className="px-3 py-1 text-sm rounded border disabled:opacity-50"
          >
            Next
          </button>
        </div>

      </div>
    </div>
  );
}
